int main() {
    Timer timer;
    std::cout << "Initial time: " << timer.getElapsedTimeMs() << "ms\n";

    timer.start();
    std::this_thread::sleep_for(std::chrono::milliseconds(100));
    timer.stop();
    std::cout << "After 100ms run: " << timer.getElapsedTimeMs() << "ms\n";

    timer.reset().start();
    std::this_thread::sleep_for(std::chrono::milliseconds(50));
    timer.stop();
    std::cout << "After reset and 50ms run: " << timer.getElapsedTimeMs() << "ms\n";

    Timer timer_chain_test;
    timer_chain_test.start();
    std::this_thread::sleep_for(std::chrono::milliseconds(75));
    timer_chain_test.stop();
    timer_chain_test.reset().start().stop(); 
    std::cout << "Timer (after chained reset().start().stop()): " << timer_chain_test.getElapsedTimeMs() << "ms\n";

    Timer timer2;
    timer2.start(); 
    std::this_thread::sleep_for(std::chrono::milliseconds(50));
    timer2.stop().reset(); 
    std::this_thread::sleep_for(std::chrono::milliseconds(50));
    std::cout << "Timer2 after stop().reset() (expected ~50 if reset, actual ~100 if not): " << timer2.getElapsedTimeMs() << "ms\n";

    return 0;
}
